Props (properties) are how you pass data from parent to child components.

**Passing Props:**
```jsx
// Parent Component
function App() {
  const name = 'John';
  const age = 25;

  return (
    <div>
      <Greeting name={name} age={age} />
    </div>
  );
}

// Child Component
function Greeting(props) {
  return <h1>Hello, {props.name}! You are {props.age} years old.</h1>;
}
```

**Destructuring Props:**
```jsx
function Greeting({ name, age }) {
  return <h1>Hello, {name}! You are {age} years old.</h1>;
}
```

**Default Props:**
```jsx
function Greeting({ name = 'Guest', age = 0 }) {
  return <h1>Hello, {name}! You are {age} years old.</h1>;
}

// Usage
<Greeting />  // Hello, Guest! You are 0 years old.
<Greeting name="John" age={25} />  // Hello, John! You are 25 years old.
```

**Props are Read-Only:**
```jsx
// WRONG - Props cannot be modified
function Greeting({ name }) {
  name = 'New Name'; // Error!
  return <h1>Hello, {name}</h1>;
}

// CORRECT - Use state for mutable data
function Greeting({ initialName }) {
  const [name, setName] = useState(initialName);
  return <h1>Hello, {name}</h1>;
}
```

State is data that can change over time within a component.

**Using useState Hook:**
```jsx
import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>Increment</button>
    </div>
  );
}
```

**State Rules:**
- State is private to the component
- State changes trigger re-renders
- Never modify state directly
- State updates are asynchronous

**Multiple State Variables:**
```jsx
function UserForm() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [age, setAge] = useState(0);

  return (
    <form>
      <input 
        value={name} 
        onChange={(e) => setName(e.target.value)} 
      />
      <input 
        value={email} 
        onChange={(e) => setEmail(e.target.value)} 
      />
      <input 
        type="number"
        value={age} 
        onChange={(e) => setAge(parseInt(e.target.value))} 
      />
    </form>
  );
}
```

**Object State:**
```jsx
function UserForm() {
  const [user, setUser] = useState({
    name: '',
    email: '',
    age: 0
  });

  const handleChange = (e) => {
    setUser({
      ...user,
      [e.target.name]: e.target.value
    });
  };

  return (
    <form>
      <input 
        name="name"
        value={user.name} 
        onChange={handleChange} 
      />
    </form>
  );
}
```

Understanding when to use props vs state is crucial in React.

**Props:**
- Passed from parent to child
- Read-only (immutable)
- External to component
- Used for configuration
- Changes trigger re-render

**State:**
- Managed within component
- Mutable (can change)
- Internal to component
- Used for dynamic data
- Changes trigger re-render

**Example - Props:**
```jsx
function Button({ label, onClick }) {
  return <button onClick={onClick}>{label}</button>;
}

function App() {
  return <Button label="Click me" onClick={() => alert('Clicked!')} />;
}
```

**Example - State:**
```jsx
function Toggle() {
  const [isOn, setIsOn] = useState(false);

  return (
    <button onClick={() => setIsOn(!isOn)}>
      {isOn ? 'ON' : 'OFF'}
    </button>
  );
}
```

**When to Use Which:**
- Use props for data that doesn't change within the component
- Use state for data that changes over time
- Use props for parent-child communication
- Use state for component-specific data

Forms are a common use case for state in React.

**Controlled Components:**
```jsx
function LoginForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Email:', email, 'Password:', password);
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        placeholder="Email"
      />
      <input
        type="password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        placeholder="Password"
      />
      <button type="submit">Login</button>
    </form>
  );
}
```

**Select Dropdown:**
```jsx
function SelectForm() {
  const [selectedOption, setSelectedOption] = useState('');

  return (
    <select 
      value={selectedOption} 
      onChange={(e) => setSelectedOption(e.target.value)}
    >
      <option value="">Choose an option</option>
      <option value="option1">Option 1</option>
      <option value="option2">Option 2</option>
    </select>
  );
}
```

**Checkbox:**
```jsx
function CheckboxForm() {
  const [isChecked, setIsChecked] = useState(false);

  return (
    <label>
      <input
        type="checkbox"
        checked={isChecked}
        onChange={(e) => setIsChecked(e.target.checked)}
      />
      Accept terms
    </label>
  );
}
```

Follow best practices when updating state in React.

**Never Modify State Directly:**
```jsx
// WRONG
const [items, setItems] = useState([1, 2, 3]);
items.push(4); // Don't do this!
setItems(items);

// CORRECT
const [items, setItems] = useState([1, 2, 3]);
setItems([...items, 4]); // Create new array
```

**Functional Updates:**
```jsx
// When new state depends on old state
const [count, setCount] = useState(0);

// WRONG
setCount(count + 1);
setCount(count + 1); // Both use same count value

// CORRECT
setCount(prevCount => prevCount + 1);
setCount(prevCount => prevCount + 1); // Each gets latest value
```

**Updating Objects:**
```jsx
const [user, setUser] = useState({ name: 'John', age: 25 });

// Update specific property
setUser({ ...user, age: 26 });

// Update multiple properties
setUser(prev => ({ ...prev, name: 'Jane', age: 26 }));
```

**Updating Arrays:**
```jsx
const [items, setItems] = useState([1, 2, 3]);

// Add item
setItems([...items, 4]);

// Remove item
setItems(items.filter(item => item !== 2));

// Update item
setItems(items.map(item => item === 2 ? 20 : item));
```
